#!/usr/bin/env node
// AUTO-GENERATED by ShipIt — do not edit by hand.
//
// Reads the project's current version using the SAME logic as ShipIt's
// release-version.ts (`readPackageJsonVersion` / `readCargoTomlVersion` /
// `readPyprojectVersion` / `readVersionFile`). The release workflow scaffolded
// alongside this file invokes it to derive the tag from the version source, so
// the version CI tags can never disagree with the version ShipIt's release
// command bumped. Keep this in lockstep with release-version.ts — the
// templates-release.test.ts consistency test fails the build if they drift.
//
// Usage:  node shipit-read-version.mjs <package.json|Cargo.toml|pyproject.toml|VERSION> [path]
// Prints the bare version (e.g. "0.3.0") to stdout, or exits non-zero with a
// diagnostic on stderr when no version can be read.

import fs from "node:fs";

function readPackageJsonVersion(file) {
  try {
    const parsed = JSON.parse(fs.readFileSync(file, "utf8"));
    return typeof parsed.version === "string" && parsed.version.trim() ? parsed.version.trim() : null;
  } catch {
    return null;
  }
}

function readCargoTomlVersion(file) {
  try {
    const raw = fs.readFileSync(file, "utf8");
    const packageSection = /\[package\]([\s\S]*?)(?=\n\[|\s*$)/.exec(raw);
    if (!packageSection) return null;
    const m = /^\s*version\s*=\s*"([^"]+)"/m.exec(packageSection[1] || "");
    return m ? (m[1] ? m[1].trim() : null) : null;
  } catch {
    return null;
  }
}

function readPyprojectVersion(file) {
  try {
    const raw = fs.readFileSync(file, "utf8");
    for (const sectionRe of [/\[project\]([\s\S]*?)(?=\n\[|\s*$)/, /\[tool\.poetry\]([\s\S]*?)(?=\n\[|\s*$)/]) {
      const section = sectionRe.exec(raw);
      if (!section) continue;
      const m = /^\s*version\s*=\s*"([^"]+)"/m.exec(section[1] || "");
      if (m) return m[1] ? m[1].trim() : null;
    }
    return null;
  } catch {
    return null;
  }
}

function readVersionFile(file) {
  try {
    const raw = fs.readFileSync(file, "utf8");
    const line = (raw.split("\n")[0] || "").trim();
    return line || null;
  } catch {
    return null;
  }
}

const READERS = {
  "package.json": readPackageJsonVersion,
  "Cargo.toml": readCargoTomlVersion,
  "pyproject.toml": readPyprojectVersion,
  VERSION: readVersionFile,
};

const source = process.argv[2];
const reader = READERS[source];
if (!reader) {
  process.stderr.write("Unknown version source: " + String(source) + "\n");
  process.stderr.write("Expected one of: package.json, Cargo.toml, pyproject.toml, VERSION\n");
  process.exit(2);
}

// Default to the conventional filename in the repo root; an explicit path
// (monorepo version source) overrides it.
const file = process.argv[3] || source;
const version = reader(file);
if (!version) {
  process.stderr.write("Could not read a version from " + file + " (source: " + source + ")\n");
  process.exit(1);
}
process.stdout.write(version);
